import React, { useEffect, useState } from "react";
import API from "../../api/api";
import FreelancerLayout from "../../components/FreelancerLayout";

const categories = [
  "All",
  "Web Development",
  "Mobile Development",
  "Design",
  "Marketing",
  "Backend Development",
];

const FindProjects = () => {
  const [projects, setProjects] = useState([]);
  const [search, setSearch] = useState("");
  const [selectedCategory, setSelectedCategory] = useState("All");
  const [loading, setLoading] = useState(true);

  // ================= FETCH PROJECTS =================
  const fetchProjects = async () => {
    try {
      const res = await API.get("/projects");
      setProjects(res.data);
    } catch (err) {
      console.log(err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchProjects();
  }, []);

  // ================= SEND PROPOSAL =================
  const sendProposal = async (projectId) => {
    const bid = prompt("Enter Your Bid Amount");
    const message = prompt("Enter Proposal Message");

    if (!bid || !message) return;

    try {
      await API.post("/proposals", {
        project_id: projectId,
        bid,
        message,
      });

      alert("Proposal Sent Successfully");
    } catch (error) {
      alert("Error sending proposal");
    }
  };

  // ================= FILTER LOGIC =================
  const filteredProjects = projects.filter((project) => {
    const matchesSearch = project.title
      ?.toLowerCase()
      .includes(search.toLowerCase());

    const matchesCategory =
      selectedCategory === "All" ||
      project.category === selectedCategory;

    return matchesSearch && matchesCategory;
  });

  return (
    <FreelancerLayout>
      <div className="p-8 max-w-6xl mx-auto">

        {/* HEADER */}
        <h1 className="text-3xl font-bold mb-6">Find Projects</h1>

        {/* SEARCH + FILTERS */}
        <div className="flex flex-col lg:flex-row gap-4 lg:items-center mb-8">

          {/* Search */}
          <input
            type="text"
            placeholder="Search projects..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="flex-1 px-4 py-3 border rounded-xl shadow-sm focus:outline-none focus:ring-2 focus:ring-green-400"
          />

          {/* Categories */}
          <div className="flex flex-wrap gap-3">
            {categories.map((cat) => (
              <button
                key={cat}
                onClick={() => setSelectedCategory(cat)}
                className={`px-4 py-2 rounded-full text-sm font-medium transition
                  ${
                    selectedCategory === cat
                      ? "bg-green-500 text-white"
                      : "bg-gray-100 hover:bg-gray-200"
                  }`}
              >
                {cat}
              </button>
            ))}
          </div>
        </div>

        {loading && <p>Loading projects...</p>}

        {!loading && filteredProjects.length === 0 && (
          <p>No Projects Found</p>
        )}

        {/* PROJECT LIST (LIKE IMAGE 2) */}
        <div className="space-y-6">
          {filteredProjects.map((project) => (
            <div
              key={project.id}
              className="bg-white p-6 rounded-2xl shadow hover:shadow-lg transition"
            >
              {/* TOP ROW */}
              <div className="flex justify-between items-start">

                <div>
                  <h3 className="text-xl font-semibold">
                    {project.title}
                  </h3>

                  <p className="text-gray-600 mt-2">
                    {project.description}
                  </p>
                </div>

                <span className="bg-green-100 text-green-600 px-3 py-1 text-sm rounded-full">
                  open
                </span>
              </div>

              {/* SKILLS (if exists) */}
              {project.skills && (
                <div className="flex flex-wrap gap-2 mt-4">
                  {project.skills.split(",").map((skill, index) => (
                    <span
                      key={index}
                      className="bg-gray-100 px-3 py-1 text-sm rounded-full"
                    >
                      {skill}
                    </span>
                  ))}
                </div>
              )}

              {/* FOOTER INFO */}
              <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center mt-6 pt-4 border-t">

                <div className="flex flex-wrap gap-6 text-gray-600 text-sm">

                  <span>₹ {project.budget}</span>

                  {project.deadline && (
                    <span>{project.deadline}</span>
                  )}

                  {project.company && (
                    <span>{project.company}</span>
                  )}
                </div>

                <div className="flex items-center gap-6 mt-4 lg:mt-0">

                  <span className="text-green-600 font-medium text-sm">
                    {project.proposalsCount || 0} proposals
                  </span>

                  <button
                    onClick={() => sendProposal(project.id)}
                    className="bg-green-500 text-white px-4 py-2 rounded-lg hover:bg-green-600 transition"
                  >
                    Apply
                  </button>

                </div>

              </div>

            </div>
          ))}
        </div>

      </div>
    </FreelancerLayout>
  );
};

export default FindProjects;
